import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Helmet } from 'react-helmet-async';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, PaymentElement, useStripe, useElements } from '@stripe/react-stripe-js';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import { apiMessage } from '../lib/api';

const pk = process.env.REACT_APP_STRIPE_PUBLISHABLE_KEY || '';
const stripePromise = pk ? loadStripe(pk) : null;

function CheckoutPaymentForm({ shippingAddress, onSuccess }) {
  const stripe = useStripe();
  const elements = useElements();
  const [busy, setBusy] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!stripe || !elements) return;
    setBusy(true);
    try {
      const { error, paymentIntent } = await stripe.confirmPayment({
        elements,
        confirmParams: {
          return_url: `${window.location.origin}/account/orders`
        },
        redirect: 'if_required'
      });
      if (error) {
        toast.error(error.message || 'Payment failed');
        return;
      }
      const pi = paymentIntent;
      if (!pi?.id) {
        toast.error('Payment was not completed');
        return;
      }
      const confirmRes = await axios.post(
        '/api/orders/confirm',
        {
          paymentIntentId: pi.id,
          shippingAddress
        },
        { withCredentials: true }
      );
      toast.success('Order placed — thank you!');
      onSuccess();
      const orderId = confirmRes?.data?.data?.order?._id;
      navigate(orderId ? `/order-confirmation/${orderId}` : '/account/orders');
    } catch (err) {
      toast.error(apiMessage(err, 'Could not complete order'));
    } finally {
      setBusy(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="checkout-payment-form">
      <PaymentElement />
      <button type="submit" className="btn btn-gold btn-full" disabled={!stripe || busy}>
        {busy ? 'Processing…' : 'Pay securely'}
      </button>
    </form>
  );
}

export default function Checkout() {
  const navigate = useNavigate();
  const { cart, cartState, loading, fetchCart, getSubtotal } = useCart();
  const [deliveryOption, setDeliveryOption] = useState('standard');
  const [shippingAddress, setShippingAddress] = useState({
    firstName: '',
    lastName: '',
    street: '',
    city: '',
    state: '',
    zipCode: '',
    country: 'United Kingdom',
    phone: ''
  });
  const [clientSecret, setClientSecret] = useState(null);
  const [creatingPi, setCreatingPi] = useState(false);

  const totals = cartState.totals;

  const startPayment = async () => {
    if (!cart.length) {
      toast.error('Your cart is empty');
      return;
    }
    if (!stripePromise) {
      toast.error('Stripe is not configured. Set REACT_APP_STRIPE_PUBLISHABLE_KEY in .env');
      return;
    }
    setCreatingPi(true);
    try {
      const res = await axios.post(
        '/api/stripe/create-payment-intent',
        {
          deliveryOption,
          shippingAddress
        },
        { withCredentials: true }
      );
      const secret = res.data?.data?.clientSecret;
      if (!secret) {
        toast.error(res.data?.message || 'Could not start payment');
        return;
      }
      setClientSecret(secret);
      toast.success('Enter your card details below');
    } catch (err) {
      toast.error(apiMessage(err, 'Payment setup failed'));
    } finally {
      setCreatingPi(false);
    }
  };

  const handlePaidSuccess = () => {
    fetchCart();
  };

  if (loading) {
    return (
      <main className="section container">
        <p>Loading cart…</p>
      </main>
    );
  }

  if (!cart.length) {
    return (
      <main className="section container text-center">
        <Helmet>
          <title>Checkout | Nova Shop</title>
        </Helmet>
        <h1>Your cart is empty</h1>
        <Link to="/shop" className="btn btn-primary">
          Continue shopping
        </Link>
      </main>
    );
  }

  return (
    <main className="section checkout-page">
      <Helmet>
        <title>Checkout | Nova Shop</title>
      </Helmet>
      <div className="container">
        <header className="page-header" style={{ paddingBottom: 0 }}>
          <h1>Checkout</h1>
          <ol className="breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li>
              <Link to="/cart">Cart</Link>
            </li>
            <li className="active">Checkout</li>
          </ol>
        </header>

        {!pk && (
          <div className="api-error-banner" role="alert">
            <p>
              <strong>Stripe publishable key missing.</strong> Add{' '}
              <code>REACT_APP_STRIPE_PUBLISHABLE_KEY</code> to <code>frontend/.env</code> and restart
              the dev server.
            </p>
          </div>
        )}

        <div className="checkout-layout">
          <div className="checkout-shipping card-like">
            <h2>Delivery</h2>
            <div className="form-group">
              <label className="form-label">Option</label>
              <div className="delivery-options">
                {[
                  ['standard', 'Standard (3–5 days)'],
                  ['express', 'Express (1–2 days)'],
                  ['nextday', 'Next day']
                ].map(([val, label]) => (
                  <label key={val} className="delivery-option-label">
                    <input
                      type="radio"
                      name="delivery"
                      value={val}
                      checked={deliveryOption === val}
                      onChange={() => setDeliveryOption(val)}
                    />
                    {label}
                  </label>
                ))}
              </div>
            </div>
            <h3>Shipping address</h3>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">First name</label>
                <input
                  className="form-control"
                  value={shippingAddress.firstName}
                  onChange={(e) =>
                    setShippingAddress((s) => ({ ...s, firstName: e.target.value }))
                  }
                />
              </div>
              <div className="form-group">
                <label className="form-label">Last name</label>
                <input
                  className="form-control"
                  value={shippingAddress.lastName}
                  onChange={(e) =>
                    setShippingAddress((s) => ({ ...s, lastName: e.target.value }))
                  }
                />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Street</label>
              <input
                className="form-control"
                value={shippingAddress.street}
                onChange={(e) => setShippingAddress((s) => ({ ...s, street: e.target.value }))}
              />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">City</label>
                <input
                  className="form-control"
                  value={shippingAddress.city}
                  onChange={(e) => setShippingAddress((s) => ({ ...s, city: e.target.value }))}
                />
              </div>
              <div className="form-group">
                <label className="form-label">Postcode</label>
                <input
                  className="form-control"
                  value={shippingAddress.zipCode}
                  onChange={(e) => setShippingAddress((s) => ({ ...s, zipCode: e.target.value }))}
                />
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Phone</label>
              <input
                className="form-control"
                value={shippingAddress.phone}
                onChange={(e) => setShippingAddress((s) => ({ ...s, phone: e.target.value }))}
              />
            </div>

            {!clientSecret && (
              <button
                type="button"
                className="btn btn-primary btn-full"
                onClick={startPayment}
                disabled={creatingPi || !pk}
              >
                {creatingPi ? 'Preparing payment…' : 'Continue to payment'}
              </button>
            )}
          </div>

          <aside className="checkout-summary card-like">
            <h2>Order summary</h2>
            <ul className="checkout-lines">
              {cart.map((line) => (
                <li key={line.product?._id || line.product}>
                  <span>
                    {line.product?.name} × {line.quantity}
                  </span>
                  <span>
                    £
                    {Number(line.lineTotal ?? (line.price || 0) * (line.quantity || 0)).toFixed(2)}
                  </span>
                </li>
              ))}
            </ul>
            <div className="summary-row">
              <span>Subtotal</span>
              <span>£{getSubtotal().toFixed(2)}</span>
            </div>
            {totals && (
              <>
                <div className="summary-row">
                  <span>Discount</span>
                  <span>−£{Number(totals.discountAmount || 0).toFixed(2)}</span>
                </div>
                <div className="summary-row total">
                  <span>Total</span>
                  <span>£{Number(totals.total || 0).toFixed(2)}</span>
                </div>
              </>
            )}
            <button type="button" className="btn btn-outline btn-sm" onClick={() => navigate('/cart')}>
              Edit cart
            </button>

            {clientSecret && stripePromise && (
              <div className="checkout-stripe-wrap">
                <h3>Payment</h3>
                <Elements stripe={stripePromise} options={{ clientSecret }}>
                  <CheckoutPaymentForm
                    shippingAddress={shippingAddress}
                    onSuccess={handlePaidSuccess}
                  />
                </Elements>
              </div>
            )}
          </aside>
        </div>
      </div>
    </main>
  );
}
